  const cashDelta = clamp(cashflow * decayRate, M05_BOUNDS.MIN_CASH_DELTA, M05_BOUNDS.MAX_CASH_DELTA);
  const regimeShift = Math.abs(cashDelta) > M05_BOUNDS.REGIME_SHIFT_THRESHOLD;
    emit({ event: 'MACRO_REGIME_SHIFT', mechanic_id: 'M05', tick: currentTick, runId: '', payload: { cashDelta, decayRate, macroRegime } });
